const SetValue = async (context) => {
    // Build warranty list - most efficient for single-threaded
    const warranties = [];

    // Direct field access with early evaluation
    if (context?.Form?.Page1?.HVACCheckbox?.Value) 
        warranties.push("HVAC Warranty: Five (5) Years Parts and Labor");

    if (context?.Form?.Page1?.WaterHeaterCheckbox?.Value) 
        warranties.push("Water Heater Warranty: Five (5) Years Parts and Labor");

    if (context?.Form?.Page1?.DuctworkCheckbox?.Value) 
        warranties.push("Ductwork Warranty: One (1) Year Parts and Labor");

    if (context?.Form?.Page1?.ElectricalCheckbox?.Value) 
        warranties.push("Electrical Warranty: Two (2) Years Parts and Labor");

    if (context?.Form?.Page1?.Thermostat?.Value) 
        warranties.push("Thermostat Warranty: Two (2) Years Parts and Labor");

    if (context?.Form?.Page1?.Insulation?.Value) 
        warranties.push("Insulation Warranty: Five (5) Years Parts and Labor");

    if (context?.Form?.Page1?.AlarmsCheckbox?.Value) 
        warranties.push("Alarm Warranty: Two (2) Years Parts and Labor");

    if (context?.Form?.Page1?.ClothesDryerCheckbox?.Value) {
    const dryerType = context?.Form?.ClothesDryerWasher?.NewClothesDryerType?.Value;
    if (dryerType === "Standard") {
        warranties.push("Clothes Dryer Warranty: Two (2) Years Parts and Labor");
    } else if (dryerType === "Heat Pump") {
        warranties.push("Clothes Dryer Warranty: Five (5) Years Parts and Labor");
    }
    }

    if (context?.Form?.Page1?.CookingApplianceCheckbox?.Value) 
        warranties.push("Cooking Appliance Warranty: Two (2) Years Parts and Labor");

    if (context?.Form?.Page1?.MiniSplitCheckbox?.Value) 
        warranties.push("Mini Split Warranty: Five (5) Years Parts and Labor");

    if (context?.Form?.Page1?.MinorHomeRepair?.Value) 
        warranties.push("Minor Home Repair Warranty: Two (2) Years Parts and Labor");

    if (context?.Form?.Page1?.RoomACEVAPCoolerCheckbox?.Value) 
        warranties.push("Room AC/EVAP Cooler Warranty: Two (2) Years Parts and Labor");

    return warranties.join('\n');
